/* view may be a single tag or an array of tags. These normalise either form. */
window.viewList = function (v) { return Array.isArray(v) ? v : (v ? [v] : []); };
window.viewText = function (v) { return window.viewList(v).join(" \u00b7 "); };
/* Rental destination key: for "Sub-area · Region · Country" use the Region; else the first part. */
window.rentDest = function (loc) { const p = (loc || "").split(" \u00b7 ").filter(Boolean); return p.length >= 3 ? p[p.length - 2] : p[0]; };

/* Google Maps Embed API key. Leave "" to use the OpenStreetMap fallback.
   Paste a key (Google Cloud → enable "Maps Embed API") to switch every
   property map to the real, interactive Google Maps. The Embed API is free. */
